+class MinimalActionServer : public rclcpp::Node
+{
+public:
+  using Fibonacci = example_interfaces::action::Fibonacci;
+  using GoalHandleFibonacci = rclcpp_action::ServerGoalHandle<Fibonacci>;
+
+  explicit MinimalActionServer(const rclcpp::NodeOptions & options = rclcpp::NodeOptions())
+  : Node("minimal_action_server", options)
+  {
+    using namespace std::placeholders;
+    callback_group_ = this->create_callback_group(rclcpp::CallbackGroupType::Reentrant);
+
+    this->action_server_ = rclcpp_action::create_server<Fibonacci>(
+      this->get_node_base_interface(), this->get_node_clock_interface(),
+      this->get_node_logging_interface(), this->get_node_waitables_interface(), "fibonacci",
+      std::bind(&MinimalActionServer::handle_goal, this, _1, _2),
+      std::bind(&MinimalActionServer::handle_cancel, this, _1),
+      std::bind(&MinimalActionServer::handle_accepted, this, _1),
+      rcl_action_server_get_default_options(), callback_group_);
+  }
+
+private:
+  rclcpp_action::Server<Fibonacci>::SharedPtr action_server_;
+  rclcpp::CallbackGroup::SharedPtr callback_group_;
+  std::mutex goal_mutex_;
+  std::shared_ptr<GoalHandleFibonacci> current_goal_;
+
+  rclcpp_action::GoalResponse handle_goal(
+    const rclcpp_action::GoalUUID & uuid, std::shared_ptr<const Fibonacci::Goal> goal)
+  {
+    RCLCPP_INFO(this->get_logger(), "Received goal request with order %d", goal->order);
+    (void)uuid;
+    return rclcpp_action::GoalResponse::ACCEPT_AND_EXECUTE;
+  }
+
+  rclcpp_action::CancelResponse handle_cancel(
+    const std::shared_ptr<GoalHandleFibonacci> goal_handle)
+  {
+    RCLCPP_INFO(this->get_logger(), "Received request to cancel goal");
+    (void)goal_handle;
+    return rclcpp_action::CancelResponse::ACCEPT;
+  }
+
+  void execute(const std::shared_ptr<GoalHandleFibonacci> goal_handle)
+  {
+    RCLCPP_INFO(this->get_logger(), "Executing goal");
+    rclcpp::Rate loop_rate(1);
+    const auto goal = goal_handle->get_goal();
+    auto feedback = std::make_shared<Fibonacci::Feedback>();
+    auto & sequence = feedback->sequence;
+    sequence.push_back(0);
+    sequence.push_back(1);
+    auto result = std::make_shared<Fibonacci::Result>();
+
+    for (int i = 1; (i < goal->order) && rclcpp::ok(); ++i) {
+      // If goal is flagged as no longer active (ie. another goal was accepted),
+      // then stop executing
+      if (!goal_handle->is_active()) {
+        RCLCPP_INFO(this->get_logger(), "Goal aborted");
+        return;
+      }
+
+      // Check if there is a cancel request
+      if (goal_handle->is_canceling()) {
+        result->sequence = sequence;
+        goal_handle->canceled(result);
+        RCLCPP_INFO(this->get_logger(), "Goal Canceled");
+        return;
+      }
+      // Update sequence
+      sequence.push_back(sequence[i] + sequence[i - 1]);
+      // Publish feedback
+      goal_handle->publish_feedback(feedback);
+      RCLCPP_INFO(this->get_logger(), "Publish Feedback");
+
+      loop_rate.sleep();
+    }
+
+    // Check if goal is done
+    if (rclcpp::ok()) {
+      if (!goal_handle->is_active()) {
+        RCLCPP_INFO(this->get_logger(), "Goal aborted");
+        return;
+      }
+
+      result->sequence = sequence;
+      goal_handle->succeed(result);
+      RCLCPP_INFO(this->get_logger(), "Goal Succeeded");
+    }
+  }
+
+  void handle_accepted(const std::shared_ptr<GoalHandleFibonacci> goal_handle)
+  {
+    {
+      std::lock_guard<std::mutex> lock(goal_mutex_);
+      // This server only allows one goal at a time
+      if (current_goal_ && current_goal_->is_active()) {
+        RCLCPP_INFO(this->get_logger(), "Aborting previous goal");
+        auto aborted_result = std::make_shared<Fibonacci::Result>();
+        // Abort the existing goal
+        current_goal_->abort(aborted_result);
+      }
+      current_goal_ = goal_handle;
+    }
+
+    using namespace std::placeholders;
+    // this needs to return quickly to avoid blocking the executor, so spin up a new thread
+    std::thread{std::bind(&MinimalActionServer::execute, this, _1), goal_handle}.detach();
+  }
+};  // class MinimalActionServer
+
+int main(int argc, char ** argv)
+{
+  rclcpp::init(argc, argv);
+
+  auto action_server = std::make_shared<MinimalActionServer>();
+
+  // We use a MultiThreadedExecutor to handle incoming goal requests concurrently
+  rclcpp::executors::MultiThreadedExecutor executor;
+  executor.add_node(action_server);
+  executor.spin();
+  rclcpp::shutdown();
+  return 0;
+}

